    op.create_table('coupons',
    sa.Column('code', sa.String(length=50), nullable=False, comment='Uppercase alphanumeric code entered by customers at checkout. Service layer normalizes input to uppercase before lookup.'),
    sa.Column('title', sa.String(length=200), nullable=False, comment="Customer-visible name e.g. 'DIWALI2024 – 15% off all bookings'."),
    sa.Column('description', sa.Text(), nullable=True, comment='Customer-visible description with eligibility summary and terms.'),
    sa.Column('coupon_type', sa.Enum('PERCENTAGE', 'FIXED_AMOUNT', 'FREE_SERVICE', 'CASHBACK', name='coupon_type', native_enum=False), nullable=False),
    sa.Column('applicability', sa.Enum('ALL', 'FIRST_BOOKING', 'SPECIFIC_CATEGORY', 'SPECIFIC_VENDOR', 'SPECIFIC_PACKAGE', 'MEMBERSHIP_ONLY', name='coupon_applicability', native_enum=False), nullable=False),
    sa.Column('discount_value', sa.Numeric(precision=10, scale=2), nullable=False, comment='For PERCENTAGE: percentage to deduct (e.g., 15.00 = 15%). For FIXED_AMOUNT / CASHBACK: monetary amount in `currency`.'),
    sa.Column('max_discount_amount', sa.Numeric(precision=10, scale=2), nullable=True, comment='Maximum monetary discount allowed for PERCENTAGE coupons. NULL means uncapped. Irrelevant for FIXED_AMOUNT coupons.'),
    sa.Column('currency', sa.Enum('INR', 'USD', 'EUR', 'GBP', 'AED', 'SGD', name='currency', native_enum=False), nullable=False),
    sa.Column('min_order_value', sa.Numeric(precision=12, scale=2), nullable=True, comment='Minimum order subtotal required to use this coupon.'),
    sa.Column('first_booking_only', sa.Boolean(), nullable=False, comment='If True, only customers with zero prior completed bookings can redeem.'),
    sa.Column('eligible_membership_tiers', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment="MembershipTier values allowed to use this coupon. NULL means all tiers. Example: ['gold', 'platinum']."),
    sa.Column('applicable_vendor_ids', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment='UUID strings of vendors this coupon applies to. NULL means all vendors.'),
    sa.Column('applicable_package_ids', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment='UUID strings of packages this coupon applies to. NULL means all packages.'),
    sa.Column('applicable_occasion_categories', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment="OccasionCategory values this coupon applies to. NULL means all categories. Example: ['life_event', 'major_festival']."),
    sa.Column('total_usage_limit', sa.Integer(), nullable=True, comment='Maximum total redemptions across all customers. NULL means unlimited.'),
    sa.Column('per_user_limit', sa.Integer(), nullable=True, comment='Maximum times a single customer can use this coupon. NULL means once (most common); set to higher for multi-use coupons.'),
    sa.Column('times_used', sa.Integer(), nullable=False, comment='Denormalized total redemption count. Incremented under FOR UPDATE lock. Must not exceed total_usage_limit when total_usage_limit IS NOT NULL.'),
    sa.Column('is_active', sa.Boolean(), nullable=False, comment='False immediately disables the coupon without waiting for valid_until.'),
    sa.Column('valid_from', sa.DateTime(timezone=True), nullable=False, comment='Coupon is not redeemable before this timestamp.'),
    sa.Column('valid_until', sa.DateTime(timezone=True), nullable=True, comment='Coupon expires after this timestamp. NULL means it never expires.'),
    sa.Column('deactivated_at', sa.DateTime(timezone=True), nullable=True, comment='When is_active was last set to False.'),
    sa.Column('is_system_generated', sa.Boolean(), nullable=False, comment='True for coupons auto-generated by the platform (e.g., referral codes, birthday coupons, loyalty rewards).'),
    sa.Column('created_by_id', sa.UUID(), nullable=True, comment='Admin user who created this coupon. NULL for system-generated coupons.'),
    sa.Column('id', sa.UUID(), nullable=False, comment='UUID v4 primary key'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False, comment='UTC timestamp when the record was created'),
    sa.Column('updated_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False, comment='UTC timestamp of the last ORM-level update'),
    sa.Column('internal_notes', sa.Text(), nullable=True, comment='Internal ops/admin notes. Never expose via public API.'),
    sa.CheckConstraint('discount_value > 0', name=op.f('ck_coupons_ck_coupons_discount_value_positive')),
    sa.CheckConstraint('max_discount_amount IS NULL OR max_discount_amount > 0', name=op.f('ck_coupons_ck_coupons_max_discount_positive')),
    sa.CheckConstraint('min_order_value IS NULL OR min_order_value >= 0', name=op.f('ck_coupons_ck_coupons_min_order_non_negative')),
    sa.CheckConstraint('per_user_limit IS NULL OR per_user_limit > 0', name=op.f('ck_coupons_ck_coupons_per_user_limit_positive')),
    sa.CheckConstraint('times_used >= 0', name=op.f('ck_coupons_ck_coupons_times_used_non_negative')),
    sa.CheckConstraint('total_usage_limit IS NULL OR total_usage_limit > 0', name=op.f('ck_coupons_ck_coupons_usage_limit_positive')),
    sa.ForeignKeyConstraint(['created_by_id'], ['users.id'], name=op.f('fk_coupons_created_by_id_users'), ondelete='SET NULL'),
    sa.PrimaryKeyConstraint('id', name=op.f('pk_coupons')),
    sa.UniqueConstraint('code', name='uq_coupons_code'),
    sa.UniqueConstraint('code', name=op.f('uq_coupons_code'))
    )
    op.create_index('ix_coupons_applicability', 'coupons', ['applicability'], unique=False)
    op.create_index('ix_coupons_coupon_type', 'coupons', ['coupon_type'], unique=False)
    op.create_index(op.f('ix_coupons_is_active'), 'coupons', ['is_active'], unique=False)
