    op.create_table('audit_logs',
    sa.Column('actor_id', sa.UUID(), nullable=True, comment='Admin who performed the action. NULL for system-generated entries (cron, webhooks, automated processes). SET NULL on Admin deletion to preserve audit trail integrity.'),
    sa.Column('actor_type', sa.String(length=50), nullable=False, comment="Classification of the actor. One of: 'admin', 'system', 'cron', 'api_key'. Checked via constraint ck_audit_logs_actor_type_valid."),
    sa.Column('actor_display', sa.String(length=200), nullable=True, comment="Snapshot of the actor's display name at action time (e.g. 'Priya S. (Finance Manager)'). Preserved even if the admin account is later deactivated or renamed."),
    sa.Column('action', sa.Enum('CREATE', 'UPDATE', 'DELETE', 'SOFT_DELETE', 'RESTORE', 'LOGIN', 'LOGOUT', 'LOGIN_FAILED', 'APPROVE', 'REJECT', 'EXPORT', 'IMPORT', 'ASSIGN', 'REVOKE', 'SUSPEND', 'ACTIVATE', 'ARCHIVE', 'VIEW_SENSITIVE', 'BULK_ACTION', name='audit_action', native_enum=False), nullable=False, comment='Type of action performed'),
    sa.Column('entity_type', sa.String(length=100), nullable=False, comment="Type of the affected entity. Matches the domain name (e.g. 'booking', 'vendor', 'user', 'payment', 'admin_role', 'app_setting', 'coupon')."),
    sa.Column('entity_id', sa.UUID(), nullable=True, comment="UUID of the affected entity. NULL for list-level or schema-level actions (e.g. 'export all users', 'maintenance mode toggle')."),
    sa.Column('entity_display', sa.String(length=500), nullable=True, comment="Human-readable snapshot of the entity at action time. Examples: 'Booking TYH-001234', 'Vendor: Shree Decorators (id=...)'. Preserved for readability after the entity name changes."),
    sa.Column('before_value', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment='JSON snapshot of the entity state BEFORE the action. NULL for CREATE actions. Sensitive fields must be masked before storing (handled by service layer).'),
    sa.Column('after_value', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment='JSON snapshot of the entity state AFTER the action. NULL for DELETE / SOFT_DELETE actions.'),
    sa.Column('changed_fields', postgresql.ARRAY(sa.String(length=100)), nullable=True, comment="List of field names that changed in an UPDATE action. Allows filtered queries without parsing full JSONB diffs (e.g. find all audit logs where 'status' changed)."),
    sa.Column('ip_address', sa.String(length=50), nullable=True, comment='IPv4 or IPv6 address of the admin making the request'),
    sa.Column('user_agent', sa.String(length=500), nullable=True, comment='User-Agent header from the admin panel HTTP request'),
    sa.Column('session_id', sa.UUID(), nullable=True, comment='Admin session UUID at the time of the action. Bare UUID — no FK to avoid coupling with the auth domain.'),
    sa.Column('request_id', sa.String(length=100), nullable=True, comment='Correlation ID from the X-Request-ID header. Links this audit entry to application logs and APM traces.'),
    sa.Column('endpoint', sa.String(length=500), nullable=True, comment="API route that triggered this action (e.g. '/admin/bookings/{id}/approve')"),
    sa.Column('http_method', sa.String(length=10), nullable=True, comment='HTTP verb of the triggering request (GET, POST, PUT, PATCH, DELETE)'),
    sa.Column('is_successful', sa.Boolean(), nullable=False, comment='True when the action completed successfully. False for failed attempts (e.g. permission denied, validation error). Failed actions are still logged for security forensics.'),
    sa.Column('failure_reason', sa.String(length=500), nullable=True, comment='Error message or reason code when is_successful = False'),
    sa.Column('is_sensitive', sa.Boolean(), nullable=False, comment='True when this log entry involves PII access, financial data, or security-sensitive operations. Triggers extended retention and restricted visibility.'),
    sa.Column('data_classification', sa.String(length=50), nullable=True, comment="Data sensitivity classification for compliance reporting. Examples: 'pii', 'financial', 'kyc', 'internal'. NULL = general."),
    sa.Column('extra_metadata', postgresql.JSONB(astext_type=sa.Text()), nullable=True, comment='Additional context that does not fit the structured columns. Examples: bulk action counts, impersonation target user ID, export filters applied, custom notes from the action handler.'),
    sa.Column('id', sa.UUID(), nullable=False, comment='UUID v4 primary key'),
    sa.Column('created_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False, comment='UTC timestamp when the record was created'),
    sa.Column('updated_at', sa.DateTime(timezone=True), server_default=sa.text('now()'), nullable=False, comment='UTC timestamp of the last ORM-level update'),
    sa.CheckConstraint("actor_type IN ('admin', 'system', 'cron', 'api_key')", name=op.f('ck_audit_logs_ck_audit_logs_actor_type_valid')),
    sa.ForeignKeyConstraint(['actor_id'], ['admins.id'], name=op.f('fk_audit_logs_actor_id_admins'), ondelete='SET NULL'),
    sa.PrimaryKeyConstraint('id', name=op.f('pk_audit_logs'))
    )
    op.create_index('ix_audit_logs_action', 'audit_logs', ['action'], unique=False)
    op.create_index('ix_audit_logs_actor_id', 'audit_logs', ['actor_id'], unique=False)
    op.create_index('ix_audit_logs_actor_id_created_at', 'audit_logs', ['actor_id', 'created_at'], unique=False)
    op.create_index('ix_audit_logs_created_at', 'audit_logs', ['created_at'], unique=False)
    op.create_index('ix_audit_logs_entity_type', 'audit_logs', ['entity_type'], unique=False)
    op.create_index('ix_audit_logs_entity_type_id', 'audit_logs', ['entity_type', 'entity_id'], unique=False)
    op.create_index('ix_audit_logs_is_sensitive', 'audit_logs', ['is_sensitive'], unique=False)
    op.create_index('ix_audit_logs_is_successful', 'audit_logs', ['is_successful'], unique=False)
